@model List<ProductReviews.Models.Product>

@{
    ViewData["Title"] = "Products";
}

<h1>Products</h1>

<div class="row">
    @foreach (var product in Model)
    {
        <div class="col-md-4 mb-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text">@product.Description</p>
                    <p class="card-text"><strong>Price:</strong> @product.Price.ToString("C")</p>
                    <a asp-action="Details" asp-route-id="@product.Id" class="btn btn-primary">View Details &amp; Reviews</a>
                </div>
            </div>
        </div>
    }
</div>

// Views/Product/Details.cshtml
@model ProductReviews.Models.ProductDetailViewModel
@using ProductReviews.Helpers

@{
    ViewData["Title"] = Model.Product.Name;
}

<div class="container mt-4">
    <!-- Product Details -->
    <div class="row mb-4">
        <div class="col-md-8">
            <h1>@Model.Product.Name</h1>
            <p class="lead">@Model.Product.Description</p>
            <h3 class="text-success">@Model.Product.Price.ToString("C")</h3>
            @if (Model.Reviews.Any())
            {
                <p>
                    <strong>Average Rating:</strong>
                    @for (int i = 1; i <= 5; i++)
                    {
                        if (i <= Math.Round(Model.AverageRating))
                        {
                            <span style="color: gold; font-size: 1.2em;">&#9733;</span>
                        }
                        else
                        {
                            <span style="color: #ccc; font-size: 1.2em;">&#9733;</span>
                        }
                    }
                    <span class="text-muted">(@Model.AverageRating / 5 from @Model.Reviews.Count review(s))</span>
                </p>
            }
        </div>
    </div>

    <hr />

    <!-- Reviews Section -->
    <div class="row">
        <div class="col-md-8">
            <h2>Customer Reviews (@Model.Reviews.Count)</h2>

            @if (TempData["SuccessMessage"] != null)
            {
                <div class="alert alert-success alert-dismissible fade show" role="alert">
                    @TempData["SuccessMessage"]
                    <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>
                </div>
            }

            @if (!Model.Reviews.Any())
            {
                <p class="text-muted">No reviews yet. Be the first to review this product!</p>
            }
            else
            {
                @foreach (var review in Model.Reviews)
                {
                    <div class="card mb-3">
                        <div class="card-body">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h5 class="card-title mb-0">@review.AuthorName</h5>
                                <small class="text-muted">@review.CreatedAt.ToString("MMMM dd, yyyy 'at' hh:mm tt")</small>
                            </div>
                            <div class="mb-2">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    if (i <= review.Rating)
                                    {
                                        <span style="color: gold;">&#9733;</span>
                                    }
                                    else
                                    {
                                        <span style="color: #ccc;">&#9733;</span>
                                    }
                                }
                            </div>
                            <div class="card-text">
                                @* Render formatted content safely - only allowed tags are inserted *@
                                @Html.Raw(ReviewFormatHelper.FormatReviewContent(review.Content))
                            </div>
                        </div>
                    </div>
                }
            }
        </div>
    </div>

    <hr />

    <!-- Submit Review Form -->
    <div class="row mb-5">
        <div class="col-md-8">
            <h2>Write a Review</h2>
            <p class="text-muted">
                You can use basic formatting: <code>**bold text**</code> for <strong>bold</strong>
                and <code>*italic text*</code> for <em>italic</em>.
            </p>

            <form asp-action="SubmitReview" method="post">
                <input type="hidden" asp-for="NewReview.ProductId" />
                <div asp-validation-summary="ModelOnly" class="text-danger"></div>

                <div class="mb-3">
                    <label asp-for="NewReview.AuthorName" class="form-label">Your Name</label>
                    <input asp-for="NewReview.AuthorName" class="form-control" placeholder="Enter your name" />
                    <span asp-validation-for="NewReview.AuthorName" class="text-danger"></span>
                </div>

                <div class="mb-3">
                    <label asp-for="NewReview.Rating" class="form-label">Rating</label>
                    <select asp-for="NewReview.Rating" class="form-select" style="width: auto;">
                        <option value="">-- Select Rating --</option>
                        <option value="5">&#9733;&#9733;&#9733;&#9733;&#9733; (5 - Excellent)</option>
                        <option value="4">&#9733;&#9733;&#9733;&#9733;&#9734; (4 - Good)</option>
                        <option value="3">&#9733;&#9733;&#9733;&#9734;&#9734; (3 - Average)</option>
                        <option value="2">&#9733;&#9733;&#9734;&#9734;&#9734; (2 - Poor)</option>
                        <option value="1">&#9733;&#9734;&#9734;&#9734;&#9734; (1 - Terrible)</option>
                    </select>
                    <span asp-validation-for="NewReview.Rating" class="text-danger"></span>
                </div>

                <div class="mb-3">
                    <label asp-for="NewReview.Content" class="form-label">Your Review</label>
                    <textarea asp-for="NewReview.Content" class="form-control" rows="5"
                              placeholder="Write your review here. Use **bold** and *italic* for formatting."></textarea>
                    <span asp-validation-for="NewReview.Content" class="text-danger"></span>
                </div>

                <button type="submit" class="btn btn-primary">Submit Review</button>
                <a asp-action="Index" class="btn btn-secondary ms-2">Back to Products</a>
            </form>
        </div>
    </div>
</div>

